final:
module RefModule(
    input clk,
    input clr_n,
    input en,
    output reg [7:0] count
);

  wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk or negedge clr_n or posedge dbg_halt)
    if (!clr_n)
        count <= 8'b00000000;
    else if (en)
        count <= count + 1;

endmodule
